/*
 * Decoder Implementation in C
 * Simulates gate-level behavior of 2-to-4 and 3-to-8 decoders
 * Includes active-low output option and cascading demonstration
 */

#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Basic logic gates
#define NOT(x) (!(x))
#define AND(a, b) ((a) && (b))
#define OR(a, b) ((a) || (b))

/*
 * 2-to-4 Line Decoder with Active-High Enable
 * Logic: Yi = E AND (minterm of A1,A0)
 * 
 * Gate-level equations:
 * Y0 = E AND NOT(A1) AND NOT(A0)
 * Y1 = E AND NOT(A1) AND A0
 * Y2 = E AND A1 AND NOT(A0)
 * Y3 = E AND A1 AND A0
 */
void decoder_2to4(int enable, int a1, int a0, int *outputs) {
 // Compute complements
 int not_a1 = NOT(a1);
 int not_a0 = NOT(a0);
 int not_enable = NOT(enable);

 // When disabled, all outputs are 0 (active-high)
 // When enabled, exactly one output is 1 based on address

 // Y0 = m0 = E' + A1'·A0' (using enable as AND)
 outputs[0] = AND(enable, AND(not_a1, not_a0));

 // Y1 = m1 = E' + A1'·A0
 outputs[1] = AND(enable, AND(not_a1, a0));

 // Y2 = m2 = E' + A1·A0'
 outputs[2] = AND(enable, AND(a1, not_a0));

 // Y3 = m3 = E' + A1·A0
 outputs[3] = AND(enable, AND(a1, a0));
}

/*
 * Active-Low 2-to-4 Decoder
 * Outputs are 0 when selected, 1 when not selected
 * Useful for cascading and memory chip selection
 */
void decoder_2to4_active_low(int enable, int a1, int a0, int *outputs) {
 // For active-low, we invert the output using NAND-style logic
 // Y0_bar = E' + (A1'·A0')' = E' + Y0 -- actually using NAND gates

 // Using DeMorgan: Y_bar = (E · minterm)'
 outputs[0] = NOT(AND(enable, AND(NOT(a1), NOT(a0))));
 outputs[1] = NOT(AND(enable, AND(NOT(a1), a0)));
 outputs[2] = NOT(AND(enable, AND(a1, NOT(a0))));
 outputs[3] = NOT(AND(enable, AND(a1, a0)));
}

/*
 * 3-to-8 Decoder using two 2-to-4 decoders
 * Uses cascading with A2 as enable selector
 * 
 * Structure:
 * - Connect A1,A0 to inputs of BOTH 2-to-4 decoders
 * - Use NOT(A2) to enable lower decoder (outputs 0-3)
 * - Use A2 to enable upper decoder (outputs 4-7)
 */
void decoder_3to8_cascaded(int enable, int a2, int a1, int a0, int *outputs) {
 int lower_outputs[4];
 int upper_outputs[4];

 // Lower decoder enabled when A2 = 0
 int enable_lower = AND(enable, NOT(a2));
 decoder_2to4(enable_lower, a1, a0, lower_outputs);

 // Upper decoder enabled when A2 = 1
 int enable_upper = AND(enable, a2);
 decoder_2to4(enable_upper, a1, a0, upper_outputs);

 // Combine outputs
 for (int i = 0; i < 4; i++) {
 outputs[i] = lower_outputs[i]; // Y0-Y3
 outputs[i + 4] = upper_outputs[i]; // Y4-Y7
 }
}

/*
 * Implement Boolean function using decoder
 * F(A,B,C) = Σm(1,3,5,6) 
 * Use 3-to-8 decoder + OR gate for minterms
 */
int implement_function_with_decoder(int a, int b, int c, int enable) {
 int decoder_outputs[8];

 // Get decoder outputs
 decoder_3to8_cascaded(enable, a, b, c, decoder_outputs);

 // OR together the required minterms: m1, m3, m5, m6
 int result = 0;
 result = OR(result, decoder_outputs[1]); // m1
 result = OR(result, decoder_outputs[3]); // m3
 result = OR(result, decoder_outputs[5]); // m5
 result = OR(result, decoder_outputs[6]); // m6

 return result;
}

// Print truth table header
void print_header(int n_outputs) {
 printf("\n%-6s", "Enable");
 for (int i = 0; i < (int)log2(n_outputs); i++) {
 printf("A%d ", i);
 }
 for (int i = n_outputs - 1; i >= 0; i--) {
 printf("Y%d ", i);
 }
 printf("\n");
 printf("%-6s", "------");
 for (int i = 0; i < (int)log2(n_outputs); i++) {
 printf("--- ");
 }
 for (int i = 0; i < n_outputs; i++) {
 printf("--- ");
 }
 printf("\n");
}

// Print a decoder row
void print_decoder_row(int enable, int *addr, int n_addr, int *outputs, int n_outputs) {
 printf("%-6d", enable);
 for (int i = 0; i < n_addr; i++) {
 printf("%d ", addr[i]);
 }
 for (int i = n_outputs - 1; i >= 0; i--) {
 printf("%d ", outputs[i]);
 }
 printf("\n");
}

int main() {
 int outputs[4];
 int outputs_3to8[8];
 int address[2];

 // ============================================
 // Test 2-to-4 Decoder
 // ============================================
 printf("========================================\n");
 printf("2-to-4 LINE DECODER (Active-High)\n");
 printf("========================================");
 print_header(4);

 for (int enable = 0; enable <= 1; enable++) {
 for (int addr = 0; addr < 4; addr++) {
 address[1] = (addr >> 1) & 1; // A1
 address[0] = addr & 1; // A0

 decoder_2to4(enable, address[1], address[0], outputs);
 print_decoder_row(enable, address, 2, outputs, 4);
 }
 }

 // ============================================
 // Test 3-to-8 Cascaded Decoder
 // ============================================
 printf("\n========================================\n");
 printf("3-to-8 DECODER (Cascaded from 2-to-4)\n");
 printf("========================================");
 print_header(8);

 for (int enable = 1; enable <= 1; enable++) { // Just enabled
 for (int addr = 0; addr < 8; addr++) {
 int a2 = (addr >> 2) & 1;
 int a1 = (addr >> 1) & 1;
 int a0 = addr & 1;
 int addr_bits[3] = {a2, a1, a0};

 decoder_3to8_cascaded(enable, a2, a1, a0, outputs_3to8);
 print_decoder_row(enable, addr_bits, 3, outputs_3to8, 8);
 }
 }

 // ============================================
 // Implement Function using Decoder
 // ============================================
 printf("\n========================================\n");
 printf("FUNCTION: F(A,B,C) = Σm(1,3,5,6)\n");
 printf("Implementation using 3-to-8 Decoder + OR\n");
 printf("========================================\n");

 printf("%-6s %-6s %-12s %s\n", "ABC", "Enable", "Decoder Out", "F (OR of m1,m3,m5,m6)");
 printf("%-6s %-6s %-12s %s\n", "---", "------", "----------", "----------------------");

 for (int enable = 0; enable <= 1; enable++) {
 for (int addr = 0; addr < 8; addr++) {
 int a = (addr >> 2) & 1;
 int b = (addr >> 1) & 1;
 int c = addr & 1;

 decoder_3to8_cascaded(enable, a, b, c, outputs_3to8);

 // Calculate function output
 int f = implement_function_with_decoder(a, b, c, enable);

 // Show which minterms are active
 char minterms[32] = "";
 if (enable && outputs_3to8[1]) strcat(minterms, "m1 ");
 if (enable && outputs_3to8[3]) strcat(minterms, "m3 ");
 if (enable && outputs_3to8[5]) strcat(minterms, "m5 ");
 if (enable && outputs_3to8[6]) strcat(minterms, "m6 ");

 printf("%d%d%d %-6d %-12s %d\n", a, b, c, enable, 
 enable ? minterms : "disabled", f);
 }
 }

 return 0;
}
